class TaskScheduler {
private:
    std::vector<std::thread*> threads;
    std::vector<std::function<void()>> tasks;

public:
    void addTask(std::function<void()> task) {
        tasks.push_back(task);
    }

    void run() {
        for (auto& task : tasks) {
            std::thread* t = new std::thread(task);
            threads.push_back(t);
        }

        for (auto& t : threads) {
            t->join();
            // Missing delete on t
        }
    }

